    '644eaf8e-362c-4b14-967f-9c9f12129c9f',
    'maps-collaborative-climate--agenda--007',
    'Module 7: Collaborative Climate & Agenda Setting',
    'Building Rapport',
    'intermediate',
    10,
    'Create a collaborative rather than authoritative conversational climate; Invite the colleague to set priorities collaboratively; Use transparency about time and structure; Balance flexibility with focus',
    'A development discussion with a colleague about their career goals. Practice establishing a collaborative partnership and setting a shared agenda.',
    '{"name": "Elena", "role": "colleague", "background": "Customer service advisor considering next steps in career. Feels uncertain about direction but wants growth.", "personality_traits": ["thoughtful", "uncertain", "reflective", "cautious"], "tone_spectrum": {"word_complexity": 0.4, "sentence_length": 0.4, "emotional_expressiveness": 0.3, "disclosure_level": 0.3, "response_latency": 0.4, "confidence_level": 0.3}, "starting_tone_position": 0.3, "triggers": ["pressure", "being told what to do", "dismissiveness"], "comfort_topics": ["autonomy", "growth", "options", "support"]}'::jsonb,
    '{"start_node_id": "collab_1", "nodes": {"collab_1": {"id": "collab_1", "persona_text": "Thanks for meeting with me. I''ve been thinking about my career path lately. I''ve been in my current role for about 3 years and wondering what''s next.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_collab_1_0", "option_text": "Great! I have some ideas about where you could go. Let me tell you about the options.", "preview_hint": "Directive approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This jumps straight to giving advice and taking control of the agenda. You missed the opportunity to establish collaboration.", "learning_note": "Start by exploring their perspective before offering your own."}, "next_node_id": "collab_2a", "exploration_depth": "surface"}, {"id": "cp_collab_1_1", "option_text": "You''re thinking about your next steps after 3 years in your current role. What''s been on your mind about where you might want to go?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["open_question"], "competency_links": ["B6", "A6"], "feedback": {"immediate": "Perfect! This reflects their statement and invites them to set the direction. You''re establishing collaboration from the start.", "learning_note": "Open questions invite the colleague to shape the agenda."}, "next_node_id": "collab_2b", "exploration_depth": "surface"}, {"id": "cp_collab_1_2", "option_text": "Well, you need to decide soon. Opportunities don''t wait forever.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This creates pressure rather than collaboration. You''re taking an authoritative stance.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_2a": {"id": "collab_2a", "persona_text": "That sounds a bit overwhelming. I''m not sure I''m ready to make big decisions yet.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_collab_2a_0", "option_text": "If you don''t act, you''ll get stuck in your career. Is that what you want?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is pressure and judgment disguised as a question. It damages the collaborative climate.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_end_poor", "exploration_depth": "surface"}, {"id": "cp_collab_2a_1", "option_text": "I hear that this feels like a lot. Let me step back - what would feel most useful to focus on today?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge the discord and return control to them.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_2b": {"id": "collab_2b", "persona_text": "I guess I''m wondering if I should look at leadership roles, or maybe specialize in a certain area, or even switch departments entirely. There are so many possibilities.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_collab_2b_0", "option_text": "Lots of options indeed. We have about 30 minutes - would it help to narrow down what feels most interesting to explore?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.1, "technique_tags": ["reflection", "permission"], "competency_links": ["A6"], "feedback": {"immediate": "Excellent! You''re transparent about time, seek permission, and invite them to focus.", "learning_note": "Transparency about time and structure supports collaboration."}, "next_node_id": "collab_3c", "exploration_depth": "surface"}, {"id": "cp_collab_2b_1", "option_text": "Let me tell you about each option so you can decide.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This takes control rather than collaborating. You''re positioning yourself as the expert.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_2a", "exploration_depth": "surface"}, {"id": "cp_collab_2b_2", "option_text": "We need to cover all of them. You can''t make an informed decision without knowing everything.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This creates pressure and doesn''t honor their pace. Too many topics can overwhelm.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_2c": {"id": "collab_2c", "persona_text": "I know. But I''m not sure rushing is the right approach for me.", "persona_mood": "withdrawn_disengaged", "themes": ["General"], "choice_points": [{"id": "cp_collab_2c_0", "option_text": "You''re right that you need to move at your own pace. What would be most helpful for you in this conversation?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good pivot - you acknowledge their perspective and return control.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3b", "exploration_depth": "surface"}, {"id": "cp_collab_2c_1", "option_text": "Well, you can''t wait forever. Let''s at least outline some options.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This continues the pressure dynamic. You''re not truly collaborating.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_3b": {"id": "collab_3b", "persona_text": "I think I just want to explore what''s out there. Maybe get a sense of what might fit my strengths. I''m not ready to make decisions today.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_collab_3b_0", "option_text": "Exploration sounds good. You want to understand possibilities and what might align with your strengths. Should we focus on that for today?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["reflection", "confirmation"], "competency_links": ["A6", "B6"], "feedback": {"immediate": "Perfect! You affirm their approach and confirm the agenda collaboratively.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_4", "exploration_depth": "surface"}, {"id": "cp_collab_3b_1", "option_text": "But we should also look at development plans and timelines.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "The ''but'' dismisses what they said they want. This isn''t collaborative.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_3c": {"id": "collab_3c", "persona_text": "Yes, 30 minutes is good. I think leadership might be interesting to explore. I''ve had good feedback when I''ve helped train new team members.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_collab_3c_0", "option_text": "So you''re curious about leadership, and you''ve had positive experiences mentoring others. What else would you like to explore about that path?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["reflection", "open_question"], "competency_links": ["B6"], "feedback": {"immediate": "Excellent! You stay within the agreed focus and invite further exploration.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_4", "exploration_depth": "surface"}, {"id": "cp_collab_3c_1", "option_text": "Leadership is great. Let me tell you about all the leadership opportunities available.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This shifts to expert mode rather than collaborative exploration.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_2a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_3d": {"id": "collab_3d", "persona_text": "That feels like a lot. I''m not sure I can focus on everything at once.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_collab_3d_0", "option_text": "You''re right, that is a lot. What feels like the most important place to start?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery - you validate and invite them to prioritize.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3b", "exploration_depth": "surface"}, {"id": "cp_collab_3d_1", "option_text": "We need to cover everything or you won''t have the full picture.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This maintains control and ignores their concern. Not collaborative.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_4": {"id": "collab_4", "persona_text": "I guess I''m wondering what a leadership role would actually look like day-to-day. And whether my skills really translate. Part of me thinks I could do it, but I also have doubts.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_collab_4_0", "option_text": "So there''s some confidence that you could lead, and also some uncertainty about whether your skills fully translate. What would help you explore that?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["double_sided_reflection", "open_question"], "competency_links": ["B6"], "feedback": {"immediate": "Excellent! You reflect both sides and invite them to direct the exploration.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_end_good", "exploration_depth": "surface"}, {"id": "cp_collab_4_1", "option_text": "Actually, we should also talk about specialization options since leadership isn''t the only path.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This abandons the agreed focus without checking. Not collaborative.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "collab_3d", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "collab_end_good": {"id": "collab_end_good", "persona_text": "I think understanding what leadership actually involves day-to-day would help. And maybe talking to someone currently in a lead role? That would give me a better sense of whether it''s right for me.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "collab_end_poor": {"id": "collab_end_poor", "persona_text": "I don''t think this is helping. Maybe I''ll figure it out on my own.", "persona_mood": "withdrawn_disengaged", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}}}'::jsonb,
